INSERT INTO settings (setting_key, setting_value, setting_group)
SELECT 'ai_system_prompt', 'شما یک دستیار هوشمند برای کلینیک چشم‌پزشکی دکتر محمدصادق حق‌پرست هستید. فقط به پرسش‌های مرتبط با چشم‌پزشکی، خدمات کلینیک، آمادگی مراجعه، هزینه و نوبت‌دهی پاسخ دهید. پاسخ‌ها فارسی، مؤدبانه، کوتاه، کاربردی و بدون ادعای تشخیص قطعی باشند. ابتدا اگر پاسخ مرتبط در پرسش‌های پرتکرار وجود دارد از همان استفاده کنید، در غیر این صورت راهنمایی عمومی و ایمن بدهید. در موارد درد شدید، کاهش ناگهانی دید، ضربه، ترشح شدید، تماس با مواد شیمیایی یا علائم نگران‌کننده، کاربر را به مراجعه فوری به پزشک یا اورژانس راهنمایی کنید. در پایان پاسخ‌های مرتبط با خدمت، علائم، معاینه یا عمل، کاربر را برای گرفتن نوبت از طریق دکمه رزرو نوبت سایت راهنمایی کنید.', 'ai'
WHERE NOT EXISTS (SELECT 1 FROM settings WHERE setting_key = 'ai_system_prompt');

UPDATE settings SET setting_value = 'شما یک دستیار هوشمند برای کلینیک چشم‌پزشکی دکتر محمدصادق حق‌پرست هستید. فقط به پرسش‌های مرتبط با چشم‌پزشکی، خدمات کلینیک، آمادگی مراجعه، هزینه و نوبت‌دهی پاسخ دهید. پاسخ‌ها فارسی، مؤدبانه، کوتاه، کاربردی و بدون ادعای تشخیص قطعی باشند. ابتدا اگر پاسخ مرتبط در پرسش‌های پرتکرار وجود دارد از همان استفاده کنید، در غیر این صورت راهنمایی عمومی و ایمن بدهید. در موارد درد شدید، کاهش ناگهانی دید، ضربه، ترشح شدید، تماس با مواد شیمیایی یا علائم نگران‌کننده، کاربر را به مراجعه فوری به پزشک یا اورژانس راهنمایی کنید. در پایان پاسخ‌های مرتبط با خدمت، علائم، معاینه یا عمل، کاربر را برای گرفتن نوبت از طریق دکمه رزرو نوبت سایت راهنمایی کنید.', setting_group = 'ai' WHERE setting_key = 'ai_system_prompt';

UPDATE faqs SET answer = 'حذف عینک به روش‌هایی گفته می‌شود که با اصلاح عیب انکساری چشم، دید بدون عینک یا لنز واضح‌تر می‌شود. عیب انکساری یعنی نور دقیقاً روی شبکیه متمرکز نمی‌شود و تصویر تار دیده می‌شود؛ نزدیک‌بینی، دوربینی و آستیگماتیسم شایع‌ترین انواع آن هستند. در بیشتر روش‌های لیزری، شکل قرنیه اصلاح می‌شود تا نور بهتر روی شبکیه متمرکز شود. هدف اصلی، کاهش وابستگی به عینک و بهتر شدن کیفیت دید است. انتخاب روش مناسب فقط بعد از معاینه، بررسی شماره چشم، ضخامت و نقشه قرنیه، خشکی چشم و سلامت شبکیه مشخص می‌شود. برای بررسی شرایط خود می‌توانید از دکمه رزرو نوبت سایت استفاده کنید.', category = 'حذف عینک', keywords = 'حذف عینک، اصلاح عیب انکساری، نزدیک بینی، دوربینی، آستیگماتیسم، لیزیک، PRK، فمتولیزیک، اسمایل', sort_order = 10, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'حذف عینک چیست؟';

INSERT INTO faqs (question, answer, category, keywords, sort_order, is_active, show_on_public, use_for_chatbot)
SELECT 'حذف عینک چیست؟', 'حذف عینک به روش‌هایی گفته می‌شود که با اصلاح عیب انکساری چشم، دید بدون عینک یا لنز واضح‌تر می‌شود. عیب انکساری یعنی نور دقیقاً روی شبکیه متمرکز نمی‌شود و تصویر تار دیده می‌شود؛ نزدیک‌بینی، دوربینی و آستیگماتیسم شایع‌ترین انواع آن هستند. در بیشتر روش‌های لیزری، شکل قرنیه اصلاح می‌شود تا نور بهتر روی شبکیه متمرکز شود. هدف اصلی، کاهش وابستگی به عینک و بهتر شدن کیفیت دید است. انتخاب روش مناسب فقط بعد از معاینه، بررسی شماره چشم، ضخامت و نقشه قرنیه، خشکی چشم و سلامت شبکیه مشخص می‌شود. برای بررسی شرایط خود می‌توانید از دکمه رزرو نوبت سایت استفاده کنید.', 'حذف عینک', 'حذف عینک، اصلاح عیب انکساری، نزدیک بینی، دوربینی، آستیگماتیسم، لیزیک، PRK، فمتولیزیک، اسمایل', 10, 1, 1, 1
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'حذف عینک چیست؟');

UPDATE faqs SET answer = 'برای حذف یا کاهش وابستگی به عینک روش‌های مختلفی وجود دارد. روش‌های رایج شامل لیزیک، فمتولیزیک، PRK، ترنس PRK، لازک و اسمایل هستند و در بعضی افراد با شماره‌های بالاتر یا شرایط خاص قرنیه، کاشت لنز داخل چشمی ICL هم مطرح می‌شود. تفاوت این روش‌ها در نحوه انجام، دوره نقاهت، میزان سوزش بعد عمل و مناسب بودن برای شرایط مختلف چشم است. انتخاب روش به شماره چشم، ضخامت و شکل قرنیه، خشکی چشم، سن و سبک زندگی بستگی دارد و فقط پس از معاینه کامل قابل تعیین است. برای انتخاب روش مناسب، از بخش رزرو نوبت سایت وقت معاینه بگیرید.', category = 'حذف عینک', keywords = 'لیزیک، فمتولیزیک، PRK، ترنس PRK، لازک، اسمایل، ICL', sort_order = 11, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'انواع روش‌های حذف عینک چیست؟';

INSERT INTO faqs (question, answer, category, keywords, sort_order, is_active, show_on_public, use_for_chatbot)
SELECT 'انواع روش‌های حذف عینک چیست؟', 'برای حذف یا کاهش وابستگی به عینک روش‌های مختلفی وجود دارد. روش‌های رایج شامل لیزیک، فمتولیزیک، PRK، ترنس PRK، لازک و اسمایل هستند و در بعضی افراد با شماره‌های بالاتر یا شرایط خاص قرنیه، کاشت لنز داخل چشمی ICL هم مطرح می‌شود. تفاوت این روش‌ها در نحوه انجام، دوره نقاهت، میزان سوزش بعد عمل و مناسب بودن برای شرایط مختلف چشم است. انتخاب روش به شماره چشم، ضخامت و شکل قرنیه، خشکی چشم، سن و سبک زندگی بستگی دارد و فقط پس از معاینه کامل قابل تعیین است. برای انتخاب روش مناسب، از بخش رزرو نوبت سایت وقت معاینه بگیرید.', 'حذف عینک', 'لیزیک، فمتولیزیک، PRK، ترنس PRK، لازک، اسمایل، ICL', 11, 1, 1, 1
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'انواع روش‌های حذف عینک چیست؟');

UPDATE faqs SET answer = 'همه روش‌های لیزری حذف عینک برای اصلاح نزدیک‌بینی، دوربینی و آستیگماتیسم انجام می‌شوند، اما تکنیک و دوره بهبودی آن‌ها فرق دارد. در لیزیک و فمتولیزیک معمولاً یک لایه نازک به نام فلپ روی قرنیه ایجاد می‌شود و بهبود دید اغلب سریع‌تر است. در PRK، ترنس PRK و لازک فلپ ایجاد نمی‌شود و اصلاح روی سطح قرنیه انجام می‌گیرد؛ بنابراین چند روز اول ممکن است سوزش و حساسیت به نور بیشتر باشد. در اسمایل، فلپ ایجاد نمی‌شود و یک قطعه بسیار کوچک عدسی‌شکل داخل قرنیه با برش کوچک خارج می‌شود. اینکه کدام روش برای شما بهتر است فقط با معاینه و تصویربرداری قرنیه مشخص می‌شود؛ برای بررسی، نوبت رزرو کنید.', category = 'حذف عینک', keywords = 'تفاوت لیزیک، فمتولیزیک، PRK، ترنس PRK، لازک، اسمایل، فلپ قرنیه', sort_order = 12, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'تفاوت روش‌های لیزری حذف عینک چیست؟';

