WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'تفاوت روش‌های لیزری حذف عینک چیست؟');

UPDATE faqs SET answer = 'بهترین روش حذف عینک برای همه یکسان نیست. انتخاب روش به شماره چشم، ثبات شماره، ضخامت و نقشه قرنیه، خشکی چشم، سن، شغل، ورزش و سبک زندگی بستگی دارد. فمتولیزیک برای بسیاری از افراد با قرنیه مناسب گزینه خوبی است، PRK یا ترنس PRK ممکن است برای قرنیه نازک‌تر یا سبک زندگی پرخطر مناسب‌تر باشد و اسمایل برای برخی موارد نزدیک‌بینی و آستیگماتیسم کاربرد دارد. بدون معاینه نمی‌شود روش قطعی پیشنهاد داد. برای تعیین روش مناسب، از طریق رزرو نوبت سایت وقت معاینه بگیرید.', category = 'حذف عینک', keywords = 'بهترین روش حذف عینک، شماره چشم، ضخامت قرنیه، خشکی چشم، سبک زندگی', sort_order = 13, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'کدام روش حذف عینک برای من مناسب است؟';

INSERT INTO faqs (question, answer, category, keywords, sort_order, is_active, show_on_public, use_for_chatbot)
SELECT 'کدام روش حذف عینک برای من مناسب است؟', 'بهترین روش حذف عینک برای همه یکسان نیست. انتخاب روش به شماره چشم، ثبات شماره، ضخامت و نقشه قرنیه، خشکی چشم، سن، شغل، ورزش و سبک زندگی بستگی دارد. فمتولیزیک برای بسیاری از افراد با قرنیه مناسب گزینه خوبی است، PRK یا ترنس PRK ممکن است برای قرنیه نازک‌تر یا سبک زندگی پرخطر مناسب‌تر باشد و اسمایل برای برخی موارد نزدیک‌بینی و آستیگماتیسم کاربرد دارد. بدون معاینه نمی‌شود روش قطعی پیشنهاد داد. برای تعیین روش مناسب، از طریق رزرو نوبت سایت وقت معاینه بگیرید.', 'حذف عینک', 'بهترین روش حذف عینک، شماره چشم، ضخامت قرنیه، خشکی چشم، سبک زندگی', 13, 1, 1, 1
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'کدام روش حذف عینک برای من مناسب است؟');

UPDATE faqs SET answer = 'عمل‌های لیزری حذف عینک معمولاً برای اصلاح نزدیک‌بینی، دوربینی و آستیگماتیسم انجام می‌شوند. در نزدیک‌بینی اجسام دور تار دیده می‌شوند، در دوربینی دید نزدیک مشکل دارد و در آستیگماتیسم تصویر ممکن است کشیده یا تار دیده شود. روش‌هایی مثل فمتولیزیک، اسمایل، PRK و Trans-PRK با تکنیک‌های متفاوت، شکل قرنیه را اصلاح می‌کنند تا نور بهتر روی شبکیه متمرکز شود. مناسب بودن این روش‌ها به نتیجه معاینه و تصویربرداری قرنیه بستگی دارد. برای بررسی شرایط خود، نوبت معاینه رزرو کنید.', category = 'حذف عینک', keywords = 'نزدیک بینی، دوربینی، آستیگماتیسم، شماره چشم، تار دید', sort_order = 14, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'عمل حذف عینک چه مشکلاتی را اصلاح می‌کند؟';

