UPDATE faqs SET answer = 'لیزیک فقط یکی از روش‌های حذف عینک است. خیلی‌ها همه روش‌های حذف عینک را لیزیک می‌نامند، اما روش‌های دیگری مثل PRK، Trans-PRK، لازک، فمتولیزیک و اسمایل هم وجود دارد. بعضی روش‌ها فلپ قرنیه دارند و بعضی ندارند؛ دوره بهبودی و میزان سوزش بعد عمل هم متفاوت است. برای انتخاب روش مناسب باید معاینه کامل، شماره چشم و وضعیت قرنیه بررسی شود. برای دریافت خدمت مناسب می‌توانید از بخش رزرو نوبت سایت وقت بگیرید.', category = 'حذف عینک', keywords = 'حذف عینک، لیزیک، PRK، Trans-PRK، لازک، فمتولیزیک، اسمایل', sort_order = 15, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'آیا حذف عینک همان لیزیک است؟';

