UPDATE faqs SET answer = 'لیزیک یک روش جراحی لیزری برای اصلاح شماره چشم است. در این روش با قطره بی‌حسی، یک لایه نازک روی قرنیه به نام فلپ ایجاد می‌شود، سپس با لیزر اگزایمر شکل قرنیه اصلاح می‌شود تا نور بهتر روی شبکیه متمرکز شود و در پایان فلپ به محل خود برمی‌گردد. لیزیک برای همه مناسب نیست و قبل از عمل باید ضخامت، شکل و سلامت قرنیه و همچنین خشکی چشم بررسی شود. برای اینکه بدانید لیزیک یا روش دیگری برای شما مناسب است، نوبت معاینه رزرو کنید.', category = 'حذف عینک', keywords = 'لیزیک، LASIK، فلپ قرنیه، لیزر اگزایمر، شماره چشم', sort_order = 16, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'لیزیک چیست؟';

