UPDATE faqs SET answer = 'ضعیف شدن یا تار شدن دید می‌تواند به علت تغییر شماره چشم، آستیگماتیسم، خشکی چشم، مشکلات قرنیه، آب مروارید یا علت‌های دیگر باشد. اگر کاهش دید ناگهانی، درد چشم، جرقه نور، سایه در دید یا مگس‌پران جدید دارید، مراجعه فوری لازم است. اگر تغییر دید تدریجی است، باید معاینه شوید تا شماره چشم، قرنیه، فشار چشم و شبکیه بررسی شود. بعد از معاینه مشخص می‌شود عینک، لنز، درمان خشکی چشم یا روش‌هایی مثل PRK، فمتولیزیک، اسمایل یا ICL برای شما مناسب است یا نه. برای بررسی دقیق‌تر از دکمه رزرو نوبت سایت استفاده کنید.', category = 'ضعیفی چشم', keywords = 'چشمم ضعیف شده، ضعیفی چشم، شماره چشم، نمره چشم، تار دید، عینک، لیزیک', sort_order = 18, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'چشمم ضعیف شده چیکار کنم؟';

