UPDATE faqs SET answer = 'سوزش چشم اغلب می‌تواند به خشکی چشم، حساسیت، استفاده از لنز، کار طولانی با موبایل و کامپیوتر یا التهاب سطح چشم مربوط باشد، اما بدون معاینه علت قطعی مشخص نمی‌شود. چشم را نمالید، اگر لنز دارید آن را خارج کنید و از مصرف خودسرانه قطره آنتی‌بیوتیک یا کورتون خودداری کنید. اگر سوزش همراه با درد شدید، کاهش دید، ترشح زیاد، حساسیت شدید به نور، ضربه یا تماس با مواد شیمیایی است، باید فوری مراجعه کنید. اگر علائم ادامه دارد، برای معاینه از بخش رزرو نوبت سایت وقت بگیرید.', category = 'خشکی چشم', keywords = 'چشمم میسوزه، سوزش چشم، خشکی چشم، خارش، قرمزی، اشک ریزش، لنز', sort_order = 19, is_active = 1, show_on_public = 1, use_for_chatbot = 1, updated_at = NOW() WHERE question = 'چشمم می‌سوزد چیکار کنم؟';

